### Problem Description

The logs integrations comes with certain global component templates that adds the support for `global@custom`, `logs@custom` etc component templates.

They also define a set of ingest pipelines, with `ignore_missing_pipelines: true`, so that the end user will create it themself only if they need it.

This has a negative side effect, that when you create a custom ingest pipeline for one of the custom input integrations, and you want to test your new pipeline by simulating it against this data stream, it fails because the simulate pipeline API does not work with the `ignore_missing_pipeline` option.

### Steps to Reproduce

```
GET /_ingest/pipeline/logs-generic-2.3.1
{
  "logs-generic-2.3.1": {
    "processors": [
      {
        "pipeline": {
          "name": "global@custom",
          "ignore_missing_pipeline": true,
          "description": "[Fleet] Global pipeline for all data streams"
        }
      },
      {
        "pipeline": {
          "name": "logs@custom",
          "ignore_missing_pipeline": true,
          "description": "[Fleet] Pipeline for all data streams of type `logs`"
        }
      },
      {
        "pipeline": {
          "name": "logs-log.integration@custom",
          "ignore_missing_pipeline": true,
          "description": "[Fleet] Pipeline for all data streams of type `logs` defined by the `log` integration"
        }
      },
      {
        "pipeline": {
          "name": "logs-generic@custom",
          "ignore_missing_pipeline": true,
          "description": "[Fleet] Pipeline for the `generic` dataset"
        }
      }
    ],
    "_meta": {
      "managed_by": "fleet",
      "managed": true,
      "package": {
        "name": "log"
      }
    }
  }
}

GET /_ingest/pipeline/logs-generic@custom
{
  "logs-generic@custom": {
    "processors": [
      {
        "set": {
          "field": "test",
          "value": "test"
        }
      }
    ]
  }
}

POST /_ingest/pipeline/logs-generic-2.3.1/_simulate?verbose=true
{
  "docs": [
    {
        "_index": "_index",
        "_id": "_id",
        "_version": "-3",
        "_source": {
          "message": "hello"
        }
      }
  ]
}

{
  "docs": [
    {
      "processor_results": [
        {
          "processor_type": "pipeline",
          "status": "error",
          "description": "[Fleet] Global pipeline for all data streams",
          "error": {
            "root_cause": [
              {
                "type": "illegal_argument_exception",
                "reason": "Pipeline processor configured for non-existent pipeline [global@custom]"
              }
            ],
            "type": "illegal_argument_exception",
            "reason": "Pipeline processor configured for non-existent pipeline [global@custom]"
          }
        }
      ]
    }
  ]
}
```

